<template><PageHeader title="方言与语音观测"/><div class="grid"><MetricCard label="活动会话" :value="metrics.activeSessions||0"/><MetricCard label="总会话" :value="metrics.totalSessions||0"/><MetricCard label="对话轮次" :value="metrics.totalTurns||0"/><MetricCard label="P95 延迟" :value="(metrics.slo?.endToEndP95Ms||0)+'ms'"/></div><div class="panel"><el-table :data="dialects"><el-table-column prop="dialect" label="方言"/><el-table-column prop="count" label="会话数"/></el-table></div></template><script setup lang="ts">import{computed,onMounted,ref}from'vue';import PageHeader from'@/components/PageHeader.vue';import MetricCard from'@/components/MetricCard.vue';import{adminApi}from'@/services/admin-api';import{dialectRows}from'@/view-models';const metrics=ref<any>({}),dialects=computed(()=>dialectRows(metrics.value));onMounted(async()=>metrics.value=await adminApi.metrics());</script>
